import{_ as t,o,c as a,a3 as n}from"./chunks/framework.BveOjhN0.js";const g=JSON.parse('{"title":"Meetings — Deployment","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Meetings — Deployment | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/meetings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Meetings — Deployment | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/meetings"}]]},"headers":[],"relativePath":"deployment/meetings.md","filePath":"deployment/meetings.md","lastUpdated":1784763175000}'),i={name:"deployment/meetings.md"};function r(s,e,d,c,l,m){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="meetings-—-deployment" tabindex="-1">Meetings — Deployment <a class="header-anchor" href="#meetings-—-deployment" aria-label="Permalink to &quot;Meetings — Deployment&quot;">​</a></h1><h2 id="migrate-only" tabindex="-1">Migrate-only <a class="header-anchor" href="#migrate-only" aria-label="Permalink to &quot;Migrate-only&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate</span></span></code></pre></div><p>Creates meetings tables, registers the <code>meetings</code> catalog module (default-included CRM), grants missing default-role permissions, and records the required <strong>Meetings → Calendar</strong> module dependency.</p><p>Do <strong>not</strong> rely on <code>db:seed</code> in production for catalog/RBAC.</p><h2 id="upgrade-from-legacy-meetings-schema" tabindex="-1">Upgrade from legacy Meetings schema <a class="header-anchor" href="#upgrade-from-legacy-meetings-schema" aria-label="Permalink to &quot;Upgrade from legacy Meetings schema&quot;">​</a></h2><p>If production still has a <strong>pre-redesign</strong> <code>meetings</code> table (for example UUID PK / <code>organizer_user_id</code> / <code>meeting_participants</code> and <strong>no</strong> <code>host_id</code>), the create migration replaces <strong>Meetings-related tables only</strong>:</p><ol><li>Drops current and legacy Meetings tables (<code>meetings</code>, <code>meeting_attendees</code>, <code>meeting_provider_connections</code>, <code>meeting_reminders</code>, plus leftovers such as <code>meeting_participants</code>, <code>meeting_notes</code>, <code>meeting_attachments</code>, <code>meeting_activities</code>, <code>meeting_user_settings</code>).</li><li>Deletes orphan <code>calendar_events</code> rows with <code>source_type = meeting</code>.</li><li>Creates the current Meetings schema.</li></ol><p>Leads, users, tenants, billing, and other modules are <strong>not</strong> dropped. After this one-time upgrade, the Meetings list is empty — recreate meetings in the UI. If the current schema (<code>host_id</code> present) is already there, the create migration is a no-op.</p><h2 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h2><p>Meeting provider <strong>client ID / client secret / webhook secret are per workspace</strong> (encrypted on <code>meeting_provider_connections</code>). They are entered in Meetings → Integrations — not set in platform <code>.env</code>.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>APP_URL</code></td><td>Builds the fixed OAuth callback: <code>/api/oauth/meetings/{provider}/callback</code> (must be <code>http://localhost…</code> or HTTPS for Google)</td></tr><tr><td><code>FRONTEND_URL</code></td><td>SPA return URL after OAuth (<code>/#/meetings?integrations=…</code>)</td></tr><tr><td><code>MEETINGS_PROVIDERS_FAKE</code></td><td>Optional local/CI only; <strong>ignored / forced off in production</strong></td></tr></tbody></table><p>Each tenant registers that platform callback URL on <strong>their</strong> Google/Zoom OAuth app, then connects the workspace account.</p><h2 id="scheduler-queues" tabindex="-1">Scheduler / queues <a class="header-anchor" href="#scheduler-queues" aria-label="Permalink to &quot;Scheduler / queues&quot;">​</a></h2><ul><li><code>crm:send-due-notifications</code> every 5 minutes must run (<code>onOneServer</code>) — delivers meeting reminders (database + web push + mail).</li><li>Queue workers must process <code>default</code> / <code>emails</code> (and any dedicated notification queues) for invite mail and <code>RetryProviderSyncJob</code>.</li><li>Web Push requires VAPID keys (<code>config/webpush.php</code>) for browser push delivery.</li><li>Meeting provider webhooks are <strong>not production-complete</strong> (ack stub only); do not configure Zoom/Google marketplace webhooks against SaleOS yet.</li></ul><h2 id="smoke" tabindex="-1">Smoke <a class="header-anchor" href="#smoke" aria-label="Permalink to &quot;Smoke&quot;">​</a></h2><ol><li>Confirm marketplace module <code>meetings</code> exists and is installed; Calendar is also installed.</li><li>Owner: <code>GET /api/tenant/v1/meetings</code> → 200.</li><li>Create meeting with <code>provider=none</code> → Calendar event with <code>source=meeting</code> for host.</li><li>Save workspace Zoom/Google <strong>Client ID + secret</strong> in Meetings → Integrations, register the shown callback URL on that OAuth app, connect the account → schedule with that provider → <code>join_url</code> present.</li><li>Set <code>reminder_offset_minutes</code> in the past for a test meeting → run <code>php artisan crm:send-due-notifications</code> → reminder notification delivered once.</li><li>Staff without <code>view_all</code> cannot list unrelated meetings.</li><li>Frontend: <code>npm run test:e2e:meetings</code> against a migrated API.</li></ol><h2 id="rollback-note" tabindex="-1">Rollback note <a class="header-anchor" href="#rollback-note" aria-label="Permalink to &quot;Rollback note&quot;">​</a></h2><p>Catalog/permission/dependency data migrations are intentionally irreversible; use a forward migration to retire the module if required.</p>',19)])])}const h=t(i,[["render",r]]);export{g as __pageData,h as default};
